import httpx, os, json

WEIBO_HOT_URL = 'https://weibo.com/ajax/side/hotSearch'
topics = []

try:
    r = httpx.get(WEIBO_HOT_URL, timeout=10, headers={'User-Agent': 'Mozilla/5.0'})
    data = r.json()
    realtime = data.get('data', {}).get('realtime', [])[:10]
    for item in realtime:
        topics.append({'source': 'weibo', 'keyword': item.get('word', ''), 'heat': item.get('num', 0), 'icon': item.get('icon_desc', '')})
except Exception as e:
    try:
        import feedparser
        feed = feedparser.parse('https://top.baidu.com/board?platform=wise&sa=pcindex_entry')
        for entry in feed.entries[:10]:
            topics.append({'source': 'baidu', 'keyword': entry.title, 'heat': 0, 'icon': ''})
    except:
        topics.append({'source': 'fallback', 'keyword': 'AI人工智能', 'heat': 9999, 'icon': '爆'})

topics.sort(key=lambda x: x['heat'], reverse=True)
selected = topics[0] if topics else {'keyword': 'AI最新进展', 'source': 'fallback', 'heat': 0, 'icon': ''}

return [{'json': {'topics': topics, 'selected': selected}}]
